84	  sessionId: string;
85	  // `reqId` on user-message entries is REQUIRED (J9): the runner stamps
86	  // it onto every `event.stream-chunk` so the host-side stream router
87	  // (Task 5/7) can deliver chunks back to the originating request. We
88	  // forward `ctx.reqId` from the agent:invoke call (which is itself the
89	  // host-handled request).
90	  entry:
91	    | { type: 'user-message'; payload: ChatMessage; reqId: string }
92	    | { type: 'cancel' };
93	}
