170	  sessionId: string;
171	  workspaceRoot: string;
172	  runnerBinary: string;
173	  /**
174	   * Owner triple — userId / agentId / agentConfig. Resolved by the
175	   * orchestrator from agents:resolve and forwarded through the sandbox
176	   * plugin so the v2 session row can be written atomically with the
177	   * session itself. The runner reads this back via session:get-config
178	   * (Task 6d).
179	   */
180	  owner: {
181	    userId: string;
182	    agentId: string;
183	    agentConfig: AgentConfig;
