191	  // Opaque URI describing how the runner reaches the host. The orchestrator
192	  // never dereferences this — it's the runner's problem to parse the scheme
193	  // and dispatch transport. See @ax/sandbox-subprocess's open-session.ts
194	  // for the contract.
195	  runnerEndpoint: string;
196	  handle: OpenSessionHandle;
