199	// ---------------------------------------------------------------------------
200	// Deferred — a Promise we can resolve/reject externally, with an idempotent
201	// `settled` guard. Using this (vs. wiring promise executors by hand) keeps
202	// the orchestrator flow readable.
203	// ---------------------------------------------------------------------------
204	
205	interface Deferred<T> {
206	  readonly promise: Promise<T>;
207	  resolve(value: T): void;
208	  reject(err: unknown): void;
209	  readonly settled: boolean;
210	}
211	
212	function newDeferred<T>(): Deferred<T> {
213	  let resolveFn: (v: T) => void = () => undefined;
214	  let rejectFn: (e: unknown) => void = () => undefined;
215	  const promise = new Promise<T>((res, rej) => {
216	    resolveFn = res;
217	    rejectFn = rej;
218	  });
219	  let settled = false;
220	  return {
221	    promise,
222	    resolve(value) {
223	      if (settled) return;
224	      settled = true;
225	      resolveFn(value);
226	    },
227	    reject(err) {
228	      if (settled) return;
229	      settled = true;
230	      rejectFn(err);
231	    },
232	    get settled() {
233	      return settled;
234	    },
235	  };
236	}
237	
238	// ---------------------------------------------------------------------------
239	// Orchestrator instance. One Map-keyed-by-sessionId for in-flight waiters:
240	// chat:end subscriber looks up the session and resolves its deferred with
241	// the runner-emitted outcome. Keyed by sessionId (not reqId) because the
242	// IPC server's per-request ctx is built from the token → session lookup and
243	// carries the SAME sessionId that the orchestrator minted — that's the
244	// stable join key across the host ⇄ runner boundary.
245	// ---------------------------------------------------------------------------
246	
247	export const PLUGIN_NAME = '@ax/chat-orchestrator';
248	const DEFAULT_CHAT_TIMEOUT_MS = 10 * 60 * 1000;
249	
250	export function createOrchestrator(
251	  bus: HookBus,
252	  config: ChatOrchestratorConfig,
253	): {
254	  runChat(ctx: AgentContext, input: ChatRunInput): Promise<AgentOutcome>;
255	  onChatEnd(ctx: AgentContext, payload: { outcome: AgentOutcome }): void;
256	  onTurnEnd(ctx: AgentContext): void;
257	} {
258	  // Waiters are tracked by ctx.reqId (server-minted, J9, unique per
259	  // agent:invoke). On the J6 routed path, two concurrent agent:invokes for the
260	  // same conversation share a sessionId — keying by sessionId would let
261	  // the second agent:invoke overwrite the first's waiter (causing the first
262	  // to time out and the second to resolve with the wrong outcome).
263	  //
264	  // Resolution paths:
265	  //   - chat:end fired by the orchestrator itself (error paths) carries
266	  //     the agent:invoke ctx → ctx.reqId matches directly.
267	  //   - chat:end fired by the IPC server (runner POSTs /event.chat-end)
268	  //     stamps a fresh per-request ctx.reqId, so the reqId lookup
269	  //     misses. We fall back via `reqIdsBySession`: when only one
270	  //     waiter exists for a given sessionId, resolve THAT waiter; when
271	  //     multiple exist (the routed-collision case), the reqId-keyed
272	  //     entry from the orchestrator self-fire wins. The fresh-spawn
273	  //     path always has exactly one waiter per sessionId.
274	  const waitersByReqId = new Map<string, Deferred<AgentOutcome>>();
275	  const reqIdsBySession = new Map<string, Set<string>>();
276	  function registerWaiter(
277	    sessionId: string,
278	    reqId: string,
279	    deferred: Deferred<AgentOutcome>,
280	  ): void {
281	    waitersByReqId.set(reqId, deferred);
282	    let set = reqIdsBySession.get(sessionId);
283	    if (set === undefined) {
284	      set = new Set();
285	      reqIdsBySession.set(sessionId, set);
286	    }
287	    set.add(reqId);
288	  }
289	  function unregisterWaiter(sessionId: string, reqId: string): void {
290	    waitersByReqId.delete(reqId);
291	    const set = reqIdsBySession.get(sessionId);
292	    if (set !== undefined) {
293	      set.delete(reqId);
294	      if (set.size === 0) reqIdsBySession.delete(sessionId);
295	    }
296	  }
297	  const chatTimeoutMs = config.chatTimeoutMs ?? DEFAULT_CHAT_TIMEOUT_MS;
298	  const oneShot = config.oneShot ?? true;
299	  // Sessions that have already been cancelled — prevents a second
300	  // chat:turn-end (from a misbehaving runner) from queueing a duplicate
301	  // cancel entry.
302	  const cancelledSessions = new Set<string>();
303	
304	  async function runChat(
305	    ctx: AgentContext,
306	    input: ChatRunInput,
307	  ): Promise<AgentOutcome> {
308	    // 1. chat:start — subscribers can veto.
309	    const startResult = await bus.fire('chat:start', ctx, {
310	      message: input.message,
311	    });
312	    if (startResult.rejected) {
313	      const outcome: AgentOutcome = {
314	        kind: 'terminated',
315	        reason: `chat:start:${startResult.reason}`,
316	      };
317	      await bus.fire('chat:end', ctx, { outcome });
318	      return outcome;
319	    }
320	
321	    // 2. agents:resolve — Week 9.5 ACL gate. EVERY chat goes through here.
322	    //    The agents plugin throws PluginError('forbidden' | 'not-found')
323	    //    when the user can't reach the named agent; we map that to a
324	    //    `terminated` outcome with `reason: 'agent-resolve:<code>'` so
325	    //    audit-log subscribers see exactly one chat:end and the call
326	    //    site can branch on the prefix.
327	    //
328	    //    A non-PluginError throw (impl bug, transport blip) gets the
329	    //    same shape with `reason: 'agent-resolve:internal'` rather than
330	    //    leaking through — agent:invoke's contract is "always returns a
331	    //    AgentOutcome", and we'd rather degrade visibly than 500 the
332	    //    whole bus.call chain.
333	    let agent: AgentRecord;
334	    try {
335	      const resolved = await bus.call<AgentsResolveInput, AgentsResolveOutput>(
336	        'agents:resolve',
337	        ctx,
338	        { agentId: ctx.agentId, userId: ctx.userId },
339	      );
340	      agent = resolved.agent;
341	    } catch (err) {
342	      const code = err instanceof PluginError ? err.code : 'internal';
343	      const outcome: AgentOutcome = {
344	        kind: 'terminated',
345	        reason: `agent-resolve:${code}`,
346	        error: err,
347	      };
348	      await bus.fire('chat:end', ctx, { outcome });
349	      return outcome;
350	    }
351	
352	    // 3. Build the agent config snapshot we'll freeze on the session.
353	    //    Per Invariant I10: this is captured ONCE at session creation;
354	    //    live edits to the agent row (via /admin/agents PATCH in Task 9)
355	    //    do not affect in-flight sessions.
356	    const agentConfig: AgentConfig = {
357	      systemPrompt: agent.systemPrompt,
358	      allowedTools: agent.allowedTools,
359	      mcpConfigIds: agent.mcpConfigIds,
360	      model: agent.model,
361	    };
362	
363	    // 4. Decide: route to existing sandbox session, or open a fresh one?
364	    //
365	    //    Task 16 (J6 — one sandbox per conversation at a time). When
366	    //    `ctx.conversationId` is set AND the row's `activeSessionId` points
367	    //    at a session that's still alive, we enqueue the new user message
368	    //    into THAT session's inbox. The runner is already attached and
369	    //    will pick it up via its long-poll `tool.inbox-pull` — no new
370	    //    sandbox spawn needed.
371	    //
372	    //    Why the orchestrator does this (not the channel layer): every
373	    //    agent:invoke already passes through the agents:resolve gate and the
374	    //    chat:start veto here. Gating routing decisions in the same place
375	    //    keeps the conversation-binding policy in ONE plugin (I4 — one
376	    //    source of truth: the conversation row's active_session_id IS
377	    //    "which sandbox is in flight").
378	    let routedSessionId: string | null = null;
379	    // Gate on the peer hooks being actually registered. CLI canary and
380	    // mcp-client e2e drive the orchestrator without @ax/conversations
381	    // loaded; in those presets we skip routing entirely. See
382	    // plugin.ts manifest comment for the full rationale.
383	    const conversationsLoaded =
384	      bus.hasService('conversations:get') &&
385	      bus.hasService('conversations:bind-session') &&
386	      bus.hasService('session:is-alive');
387	    if (ctx.conversationId !== undefined && conversationsLoaded) {
388	      // Look up the conversation row. If it's gone or foreign, fall through
389	      // to the fresh-sandbox path; the channel-web layer's get-or-create
390	      // already runs at request entry, so a not-found here is unusual but
391	      // not load-bearing for the orchestrator's logic.
392	      try {
393	        const conv = await bus.call<
394	          ConversationsGetInput,
395	          ConversationsGetOutput
396	        >('conversations:get', ctx, {
397	          conversationId: ctx.conversationId,
398	          userId: ctx.userId,
399	        });
400	        const candidate = conv.conversation.activeSessionId;
401	        if (candidate !== null && candidate.length > 0) {
402	          const aliveResult = await bus.call<
403	            SessionIsAliveInput,
404	            SessionIsAliveOutput
405	          >('session:is-alive', ctx, { sessionId: candidate });
406	          if (aliveResult.alive) {
407	            routedSessionId = candidate;
408	          }
409	          // else: stale pointer (sandbox torn down without clearing the
410	          // row, or session:terminate subscriber not yet observed). Fall
411	          // through to fresh-sandbox spawn.
412	        }
413	      } catch (err) {
414	        // not-found → fall through to fresh spawn. Anything else, log
415	        // and fall through too — J6 routing is best-effort; if the
416	        // lookup itself blows up we'd rather degrade by opening a fresh
417	        // sandbox than abort the chat.
418	        ctx.logger.warn('conversation_route_lookup_failed', {
419	          conversationId: ctx.conversationId,
420	          err: err instanceof Error ? err : new Error(String(err)),
421	        });
422	      }
423	    }
424	
425	    if (routedSessionId !== null) {
426	      // ----- Route into existing live sandbox session -----
427	      //
428	      // J6: the runner is already running. We only need to:
429	      //   1. Bind reqId on the conversation row (active_session_id stays
430	      //      the same, active_req_id updates so the SSE handler at Task 7
431	      //      can locate the in-flight stream by reqId).
432	      //   2. Register a waiter on the live sessionId.
433	      //   3. Enqueue the user message into the existing inbox.
434	      //   4. Wait for the runner to emit chat:turn-end (and chat:end on
435	      //      one-shot teardown).
436	      //
437	      // We do NOT call sandbox:open-session, do NOT call session:create,
438	      // and do NOT register a NEW handle.exited watcher — the existing
439	      // sandbox's lifecycle is owned by whoever opened it originally.
440	      const sessionId = routedSessionId;
441	
442	      // (1) Bind reqId on the conversation row. ctx.conversationId is
443	      //     known non-undefined here because we entered this branch.
444	      try {
445	        await bus.call<
446	          ConversationsBindSessionInput,
447	          ConversationsBindSessionOutput
448	        >('conversations:bind-session', ctx, {
449	          conversationId: ctx.conversationId!,
450	          sessionId,
451	          reqId: ctx.reqId,
452	        });
453	      } catch (err) {
454	        // bind-session failures shouldn't be fatal — the row may have
455	        // been deleted between the lookup and now (rare race). Log and
456	        // proceed: the chat still completes; just the SSE-by-reqId
457	        // lookup may miss. Audit-log subscribers see chat:end normally.
458	        ctx.logger.warn('conversation_bind_failed_routed', {
459	          conversationId: ctx.conversationId,
460	          sessionId,
461	          err: err instanceof Error ? err : new Error(String(err)),
462	        });
463	      }
464	
465	      // (2) Register the waiter BEFORE enqueueing — the runner may emit
466	      //     chat:turn-end almost immediately on a fast model. Keyed by
467	      //     ctx.reqId (J9, unique per agent:invoke) — see waitersByReqId
468	      //     declaration for the rationale.
469	      const deferred = newDeferred<AgentOutcome>();
470	      registerWaiter(sessionId, ctx.reqId, deferred);
471	
472	      // (3) Enqueue the user message.
473	      try {
474	        await bus.call<SessionQueueWorkInput, SessionQueueWorkOutput>(
475	          'session:queue-work',
476	          ctx,
477	          {
478	            sessionId,
479	            entry: {
480	              type: 'user-message',
481	              payload: input.message,
482	              reqId: ctx.reqId,
483	            },
484	          },
485	        );
486	      } catch (err) {
487	        unregisterWaiter(sessionId, ctx.reqId);
488	        const outcome: AgentOutcome = {
489	          kind: 'terminated',
490	          reason: 'queue-work-failed',
491	          error: err,
492	        };
493	        await bus.fire('chat:end', ctx, { outcome });
494	        return outcome;
495	      }
496	
497	      // (4) Wait for the runner. We do NOT watch `exited` here: the sandbox
498	      //     handle isn't ours. If the sandbox dies mid-turn, session:terminate
499	      //     fires, the conversations subscriber clears active_session_id, and
500	      //     the next agent:invoke on this conversation routes to fresh. The
501	      //     in-flight chat will time out via the bounded chatTimeoutMs path.
502	      let resolvedByChatEndSubscriber = true;
503	      const timeoutHandle = setTimeout(() => {
504	        deferred.reject(new ChatTimeoutError(chatTimeoutMs));
505	      }, chatTimeoutMs);
506	      timeoutHandle.unref?.();
507	
508	      let outcome: AgentOutcome;
509	      try {
510	        outcome = await deferred.promise;
511	      } catch (err) {
512	        resolvedByChatEndSubscriber = false;
513	        outcome = {
514	          kind: 'terminated',
515	          reason: err instanceof ChatTimeoutError ? 'chat-run-timeout' : 'chat-run-error',
516	          error: err,
517	        };
518	      } finally {
519	        clearTimeout(timeoutHandle);
520	        unregisterWaiter(sessionId, ctx.reqId);
521	      }
522	
523	      if (!resolvedByChatEndSubscriber) {
524	        await bus.fire('chat:end', ctx, { outcome });
525	      }
526	      // No handle.kill() — we did not open this sandbox.
527	      return outcome;
528	    }
529	
530	    // 5. Register the waiter BEFORE opening the sandbox — the runner may
531	    //    emit chat:end before open-session resolves in pathological cases
532	    //    (extremely fast runner, racey test harness). Map it now so the
533	    //    subscriber can't miss the fire. The sessionId is `ctx.sessionId`
534	    //    — the kernel-level id that the sandbox plugin will forward into
535	    //    the runner's AX_SESSION_ID env; the runner then echoes it back
536	    //    in every IPC request via the token it holds, and the IPC server
537	    //    builds ctx.sessionId from that token lookup. Stable join key.
538	    const sessionId = ctx.sessionId;
539	    const deferred = newDeferred<AgentOutcome>();
540	    registerWaiter(sessionId, ctx.reqId, deferred);
541	
542	    // 6. Open the sandbox. sandbox:open-session internally calls
543	    //    session:create (minting the session + token AND writing the v2
544	    //    owner row from the `owner` field below), starts the IPC
545	    //    listener, and spawns the runner subprocess. The token never
546	    //    returns here — it flows only into the child env (I9).
547	    //
548	    //    Workspace resolution: agent.workspaceRef is currently a
549	    //    pass-through field. Wiring `workspace:resolve-ref` is a separate
550	    //    concern that becomes load-bearing only when @ax/workspace-git
551	    //    grows multi-ref support; for the MVP we use ctx.workspace
552	    //    (already populated upstream, e.g. from the channel's session
553	    //    bootstrap) and leave workspaceRef unconsumed. A subscriber
554	    //    of `agents:resolved` could observe a mismatch — that's a Task
555	    //    16+ concern, called out here so a future reader doesn't think
556	    //    workspaceRef is silently dropped.
557	    let handle: OpenSessionHandle;
558	    try {
559	      const opened = await bus.call<OpenSessionInput, OpenSessionResult>(
560	        'sandbox:open-session',
561	        ctx,
562	        {
563	          sessionId,
564	          workspaceRoot: ctx.workspace.rootPath,
565	          runnerBinary: config.runnerBinary,
566	          owner: {
567	            userId: ctx.userId,
568	            agentId: agent.id,
569	            agentConfig,
570	          },
571	        },
572	      );
573	      handle = opened.handle;
574	    } catch (err) {
575	      unregisterWaiter(sessionId, ctx.reqId);
576	      // Best-effort: terminate the session if sandbox-subprocess managed to
577	      // create it before the spawn failed. The sandbox plugin ALREADY tears
578	      // down in most failure modes, but belt-and-suspender for the case
579	      // where a partial init leaves a token alive with no listener.
580	      await bus
581	        .call<SessionTerminateInput, Record<string, never>>(
582	          'session:terminate',
583	          ctx,
584	          { sessionId },
585	        )
586	        .catch(() => undefined);
587	      const outcome: AgentOutcome = {
588	        kind: 'terminated',
589	        reason: 'sandbox-open-failed',
590	        error: err,
591	      };
592	      await bus.fire('chat:end', ctx, { outcome });
593	      return outcome;
594	    }
595	
596	    // 7. Bind the conversation row to this fresh session (J6). Same
597	    //    reqId/sessionId pair the SSE handler (Task 7) keys off. We bind
598	    //    BEFORE enqueue so the SSE GET that races us has a chance of
599	    //    finding the row. Failures here are best-effort — agent:invoke still
600	    //    completes; only SSE-by-reqId lookup loses fidelity.
601	    //
602	    //    Only attempted when @ax/conversations is loaded (channel-web
603	    //    preset) — see the routing-decision comment above.
604	    if (ctx.conversationId !== undefined && conversationsLoaded) {
605	      try {
606	        await bus.call<
607	          ConversationsBindSessionInput,
608	          ConversationsBindSessionOutput
609	        >('conversations:bind-session', ctx, {
610	          conversationId: ctx.conversationId,
611	          sessionId,
612	          reqId: ctx.reqId,
613	        });
614	      } catch (err) {
615	        ctx.logger.warn('conversation_bind_failed_fresh', {
616	          conversationId: ctx.conversationId,
617	          sessionId,
618	          err: err instanceof Error ? err : new Error(String(err)),
619	        });
620	      }
621	    }
622	
623	    // 8. Enqueue the initial user message. If this fails, the sandbox is
624	    //    running but has nothing to work on — kill it and synthesize
625	    //    chat:end. session:terminate is fired by sandbox-subprocess's
626	    //    child-close handler, so we don't double-fire it here.
627	    try {
628	      await bus.call<SessionQueueWorkInput, SessionQueueWorkOutput>(
629	        'session:queue-work',
630	        ctx,
631	        {
632	          sessionId,
633	          entry: {
634	            type: 'user-message',
635	            payload: input.message,
636	            // J9: forward the host-minted reqId so the runner can stamp
637	            // every `event.stream-chunk` it emits while processing this
638	            // user message. ctx.reqId is created by the kernel at
639	            // agent:invoke dispatch time.
640	            reqId: ctx.reqId,
641	          },
642	        },
643	      );
644	    } catch (err) {
645	      unregisterWaiter(sessionId, ctx.reqId);
646	      try {
647	        await handle.kill();
648	      } catch {
649	        // best-effort — exited promise is what drives cleanup anyway.
650	      }
651	      const outcome: AgentOutcome = {
652	        kind: 'terminated',
653	        reason: 'queue-work-failed',
654	        error: err,
655	      };
656	      await bus.fire('chat:end', ctx, { outcome });
657	      return outcome;
658	    }
659	
660	    // 5. Await chat:end with a bounded timeout, or sandbox early-exit.
661	    //    Both failure modes synthesize a terminated outcome so audit-log
662	    //    still sees chat:end fire exactly once.
663	    //
664	    //    We track three mutually-exclusive resolution paths:
665	    //      a. chat:end fired via the bus (runner emitted event.chat-end;
666	    //         IPC server's fire flowed into our subscriber which resolved
667	    //         the deferred). The IPC server ALREADY fired chat:end — do
668	    //         not re-fire or audit-log double-counts.
669	    //      b. sandbox process exited without emitting chat-end. chat:end
670	    //         was NEVER fired — we must fire it ourselves.
671	    //      c. timeout. chat:end was NEVER fired — we must fire it ourselves.
672	    let resolvedByChatEndSubscriber = true; // set to false in the non-(a) paths
673	    const timeoutHandle = setTimeout(() => {
674	      deferred.reject(new ChatTimeoutError(chatTimeoutMs));
675	    }, chatTimeoutMs);
676	    // Don't keep the host event loop alive on a hung chat.
677	    timeoutHandle.unref?.();
678	
679	    // Sandbox exit before chat:end is a terminated outcome. Do NOT reject
680	    // the deferred — resolve it with a structured outcome so the downstream
681	    // code path (which expects AgentOutcome, not an error) stays uniform.
682	    handle.exited
683	      .then(() => {
684	        if (!deferred.settled) {
685	          resolvedByChatEndSubscriber = false;
686	          deferred.resolve({
687	            kind: 'terminated',
688	            reason: 'sandbox-exit-before-chat-end',
689	          });
690	        }
691	      })
692	      .catch(() => {
693	        // exited shouldn't reject in practice; swallow to keep the orchestrator
694	        // from crashing on a pathological sandbox provider.
695	      });
696	
697	    let outcome: AgentOutcome;
698	    try {
699	      outcome = await deferred.promise;
700	    } catch (err) {
701	      // Timeout path (or a reject we triggered explicitly). Synthesize.
702	      resolvedByChatEndSubscriber = false;
703	      outcome = {
704	        kind: 'terminated',
705	        reason: err instanceof ChatTimeoutError ? 'chat-run-timeout' : 'chat-run-error',
706	        error: err,
707	      };
708	    } finally {
709	      clearTimeout(timeoutHandle);
710	      unregisterWaiter(sessionId, ctx.reqId);
711	    }
712	
713	    // 6. If the chat:end subscriber path didn't win, the runner never
714	    //    emitted event.chat-end and the IPC server never fired chat:end.
715	    //    Fire it ourselves so audit-log etc. always see exactly one
716	    //    chat:end per agent:invoke.
717	    if (!resolvedByChatEndSubscriber) {
718	      await bus.fire('chat:end', ctx, { outcome });
719	    }
720	
721	    // 7. Kill the sandbox if it's still alive. session:terminate is fired
722	    //    by sandbox-subprocess's own child-close handler, so we don't call
723	    //    it here — that would double-fire.
724	    try {
725	      await handle.kill();
726	    } catch {
727	      // best-effort
728	    }
729	
730	    return outcome;
731	  }
732	
733	  function onChatEnd(ctx: AgentContext, payload: { outcome: AgentOutcome }): void {
734	    // Two firing paths:
735	    //   1. Orchestrator self-fire (error paths) — ctx is the agent:invoke
736	    //      ctx, so ctx.reqId matches a waitersByReqId entry directly.
737	    //   2. IPC server fires from the runner's POST /event.chat-end —
738	    //      ctx.reqId is a fresh per-request id (the IPC server stamps
739	    //      it), so the reqId lookup misses. We then fall back via the
740	    //      sessionId index. The fresh-spawn path always has exactly
741	    //      one waiter per sessionId; on the (rare) routed-collision
742	    //      case (two concurrent agent:invokes into the same alive
743	    //      sandbox), there can be multiple — we resolve the OLDEST
744	    //      reqId in insertion order (Set preserves it). That matches
745	    //      the runner's actual emit order: it processes inbox FIFO,
746	    //      so chat-end after the first user message corresponds to
747	    //      the first waiter.
748	    let deferred = waitersByReqId.get(ctx.reqId);
749	    if (deferred === undefined) {
750	      const reqIds = reqIdsBySession.get(ctx.sessionId);
751	      if (reqIds !== undefined && reqIds.size > 0) {
752	        const firstReqId = reqIds.values().next().value as string;
753	        deferred = waitersByReqId.get(firstReqId);
754	      }
755	    }
756	    if (deferred !== undefined && !deferred.settled) {
757	      deferred.resolve(payload.outcome);
758	    }
759	    // Cleanup: forget we cancelled this session, in case the same sessionId
760	    // gets reused by a later agent:invoke (shouldn't happen — ctx.sessionId is
761	    // fresh per request in practice — but the cleanup keeps the set from
762	    // growing unbounded in a long-lived host).
763	    cancelledSessions.delete(ctx.sessionId);
764	  }
765	
766	  function onTurnEnd(ctx: AgentContext): void {
767	    // One-shot mode: the runner just finished processing the single user
768	    // message and is now waiting on inbox.next() for another. We don't have
769	    // one, so queue a cancel — the runner's inbox loop will receive it,
770	    // break out of its outer loop, emit event.chat-end, and exit cleanly.
771	    //
772	    // Guards:
773	    //   - oneShot must be true (multi-message hosts opt out).
774	    //   - sessionId must be an in-flight agent:invoke (skip unrelated turn-ends).
775	    //     Waiter map is keyed by ctx.reqId, but the IPC server stamps a
776	    //     fresh ctx.reqId per request, so we check via the sessionId index.
777	    //     Cancel target is ctx.sessionId (the session we want to terminate).
778	    //   - don't double-queue per session (a runner that fires turn-end
779	    //     twice must not queue two cancels for the same session).
780	    if (!oneShot) return;
781	    const liveReqIds = reqIdsBySession.get(ctx.sessionId);
782	    if (liveReqIds === undefined || liveReqIds.size === 0) return;
783	    if (cancelledSessions.has(ctx.sessionId)) return;
784	    cancelledSessions.add(ctx.sessionId);
785	    // Fire-and-forget. If this fails (e.g. session already terminated), the
786	    // sandbox-exit path will resolve the deferred as terminated and the chat
787	    // still completes cleanly — logging is enough.
788	    void bus
789	      .call<SessionQueueWorkInput, SessionQueueWorkOutput>(
790	        'session:queue-work',
791	        ctx,
792	        { sessionId: ctx.sessionId, entry: { type: 'cancel' } },
793	      )
794	      .catch((err) => {
795	        ctx.logger.warn('one_shot_cancel_queue_failed', {
796	          sessionId: ctx.sessionId,
797	          err,
798	        });
799	      });
800	  }
801	
802	  return { runChat, onChatEnd, onTurnEnd };
803	}
804	
805	// A distinct error type so the runChat finally block can tell "we timed out"
806	// apart from "something else went wrong awaiting the deferred."
807	class ChatTimeoutError extends Error {
808	  constructor(ms: number) {
809	    super(`agent:invoke timed out after ${ms}ms`);
810	    this.name = 'ChatTimeoutError';
811	  }
812	}
