1	import { spawn, type ChildProcessByStdio } from 'node:child_process';
2	import { promises as fs, constants as fsConstants } from 'node:fs';
3	import * as os from 'node:os';
4	import * as path from 'node:path';
5	import type { Readable } from 'node:stream';
6	import { z } from 'zod';
7	import {
8	  PluginError,
9	  type AgentContext,
10	  type HookBus,
11	} from '@ax/core';
12	import { allowlistFromParent } from './env.js';
13	
14	// ---------------------------------------------------------------------------
15	// sandbox:open-session
16	//
17	// Spawns a per-session runner subprocess. The runner connects back over a unix
18	// socket whose path we create in a mode-0700 tempdir (I10). Auth token is
19	// minted via `session:create` and passed to the runner only via env — never
20	// logged at info+, never returned to the hook's caller (I9). The runner
21	// binary path must be absolute (I8); no env-var fallback, no exec-path magic.
22	//
23	// Trust boundary (I5): every tunable at this surface is either validated or
24	// drawn from the same allowlist as `sandbox:spawn`. A caller cannot inject
25	// env, argv, or cwd — argv is fixed to `node <runnerBinary>`, cwd is
26	// `workspaceRoot`, and env is the session-scoped quadruple plus the allowlist.
27	// ---------------------------------------------------------------------------
28	
29	const PLUGIN_NAME = '@ax/sandbox-subprocess';
30	const HOOK_NAME = 'sandbox:open-session';
31	const SIGKILL_DELAY_MS = 5_000;
32	
33	// Owner triple — the orchestrator resolves an agent before opening the
34	// sandbox and forwards the {userId, agentId, agentConfig} so we can pass
35	// it through to `session:create` atomically. Optional for back-compat
36	// with non-orchestrator paths (tests, ad-hoc CLI tools).
37	export const AgentConfigSchema = z.object({
38	  systemPrompt: z.string(),
39	  allowedTools: z.array(z.string()),
40	  mcpConfigIds: z.array(z.string()),
41	  model: z.string(),
42	});
43	
44	export const OpenSessionInputSchema = z.object({
45	  sessionId: z.string().min(1),
46	  workspaceRoot: z.string().regex(/^\//, 'workspaceRoot must be absolute'),
47	  runnerBinary: z.string().regex(/^\//, 'runnerBinary must be absolute'),
48	  owner: z
49	    .object({
50	      userId: z.string().min(1),
51	      agentId: z.string().min(1),
52	      agentConfig: AgentConfigSchema,
53	    })
54	    .optional(),
55	});
56	
57	export type OpenSessionInput = z.input<typeof OpenSessionInputSchema>;
58	export type OpenSessionParsed = z.infer<typeof OpenSessionInputSchema>;
59	
60	export interface OpenSessionHandle {
61	  kill(): Promise<void>;
62	  exited: Promise<{ code: number | null; signal: NodeJS.Signals | null }>;
63	  // Test/inspection only: the raw child handle. NOT part of the prod
64	  // contract — callers relying on this break on any future refactor.
65	  // Present so tests can read stdout without changing the production return
66	  // shape or polluting the workspace with marker files.
67	  readonly child?: ChildProcessByStdio<null, Readable, Readable>;
68	}
69	
70	export interface OpenSessionResult {
71	  /**
72	   * Opaque URI describing how the runner reaches the host. The provider
73	   * picks the scheme:
74	   *   - `unix:///abs/path/ipc.sock` for the in-host subprocess sandbox.
75	   *   - `http://podip:7777`        for the k8s pod sandbox (Task 14/15).
76	   *
77	   * The orchestrator and the runner's IPC client treat this as opaque —
78	   * they switch on `new URL(runnerEndpoint).protocol` to dispatch
79	   * transport. I1: no transport-specific field name leaks across the
80	   * `sandbox:open-session` boundary.
81	   */
82	  runnerEndpoint: string;
83	  handle: OpenSessionHandle;
84	}
85	
86	// Shapes of the hooks we bus.call out to. These intentionally mirror the
87	// exported types from @ax/session-inmemory and @ax/ipc-server — but we do
88	// NOT import from those sibling plugins (I2). Structural duplication is the
89	// boundary cost; a drift would surface as a runtime shape error at call time.
90	interface SessionCreateInput {
91	  sessionId: string;
92	  workspaceRoot: string;
93	  owner?: {
94	    userId: string;
95	    agentId: string;
96	    agentConfig: {
97	      systemPrompt: string;
98	      allowedTools: string[];
99	      mcpConfigIds: string[];
100	      model: string;
101	    };
102	  };
103	}
104	interface SessionCreateOutput {
105	  sessionId: string;
106	  token: string;
107	}
108	interface IpcStartInput {
109	  socketPath: string;
110	  sessionId: string;
111	}
112	interface IpcStartOutput {
113	  running: true;
114	}
115	interface SessionTerminateInput {
116	  sessionId: string;
117	}
118	interface IpcStopInput {
119	  sessionId: string;
120	}
121	interface LlmProxyStartInput {
122	  sessionId: string;
123	}
124	interface LlmProxyStartOutput {
125	  url: string;
126	  port: number;
127	}
128	interface LlmProxyStopInput {
129	  sessionId: string;
130	}
131	
132	export async function openSessionImpl(
133	  ctx: AgentContext,
134	  rawInput: unknown,
135	  bus: HookBus,
136	): Promise<OpenSessionResult> {
137	  // 1. Validate input — Zod errors surface as PluginError('invalid-payload').
138	  const parseResult = OpenSessionInputSchema.safeParse(rawInput);
139	  if (!parseResult.success) {
140	    throw new PluginError({
141	      code: 'invalid-payload',
142	      plugin: PLUGIN_NAME,
143	      hookName: HOOK_NAME,
144	      message: `invalid input: ${parseResult.error.message}`,
145	      cause: parseResult.error,
146	    });
147	  }
148	  const input: OpenSessionParsed = parseResult.data;
149	
150	  // 2. Pre-check: runner binary exists and is readable. I8 says a caller that
151	  //    forgot to configure this gets a LOUD error — don't wait for spawn()'s
152	  //    ENOENT which arrives asynchronously via 'error' event.
153	  try {
154	    await fs.access(input.runnerBinary, fsConstants.R_OK);
155	  } catch (cause) {
156	    throw new PluginError({
157	      code: 'invalid-payload',
158	      plugin: PLUGIN_NAME,
159	      hookName: HOOK_NAME,
160	      message: `runner binary not found or not readable: ${input.runnerBinary}`,
161	      cause,
162	    });
163	  }
164	
165	  // 3. Per-session tempdir — mkdtemp is mode 0700 on POSIX by default (I10).
166	  //    Socket file goes inside; only the host uid can connect.
167	  const socketDir = await fs.mkdtemp(path.join(os.tmpdir(), 'ax-ipc-'));
168	  const socketPath = path.join(socketDir, 'ipc.sock');
169	
170	  // 4. Mint session + token. The token flows to the runner as env — it is
171	  //    never returned from this hook (I9). We do NOT log the token here; if
172	  //    we need to correlate failures, we log `sessionId` instead.
173	  //
174	  //    Owner triple is forwarded into the session backend so the v2 row
175	  //    can be written atomically with v1 (Task 6b). The runner reads it
176	  //    back via session:get-config (Task 6d).
177	  let created: SessionCreateOutput;
178	  try {
179	    const sessionCreateInput: SessionCreateInput = {
180	      sessionId: input.sessionId,
181	      workspaceRoot: input.workspaceRoot,
182	    };
183	    if (input.owner !== undefined) {
184	      sessionCreateInput.owner = input.owner;
185	    }
186	    created = await bus.call<SessionCreateInput, SessionCreateOutput>(
187	      'session:create',
188	      ctx,
189	      sessionCreateInput,
190	    );
191	  } catch (err) {
192	    // Clean up tempdir so a session:create failure doesn't leak dirs.
193	    await fs.rm(socketDir, { recursive: true, force: true }).catch(() => undefined);
194	    throw err;
195	  }
196	
197	  // 5. Start the listener BEFORE spawning the runner so the runner's first
198	  //    connect can't race the server bind.
199	  try {
200	    await bus.call<IpcStartInput, IpcStartOutput>('ipc:start', ctx, {
201	      socketPath,
202	      sessionId: created.sessionId,
203	    });
204	  } catch (err) {
205	    // Tear down the session we just minted — otherwise a partially-open
206	    // session lingers with a live token and no listener.
207	    await bus
208	      .call<SessionTerminateInput, Record<string, never>>('session:terminate', ctx, {
209	        sessionId: created.sessionId,
210	      })
211	      .catch(() => undefined);
212	    await fs.rm(socketDir, { recursive: true, force: true }).catch(() => undefined);
213	    throw err;
214	  }
215	
216	  // 6. Start the LLM proxy BEFORE spawning the runner so the runner's first
217	  //    `query()` call can't race the proxy bind. A failure here rolls back
218	  //    the ipc listener and session we minted above.
219	  let proxy: LlmProxyStartOutput;
220	  try {
221	    proxy = await bus.call<LlmProxyStartInput, LlmProxyStartOutput>(
222	      'llm-proxy:start',
223	      ctx,
224	      { sessionId: created.sessionId },
225	    );
226	  } catch (err) {
227	    await bus
228	      .call<IpcStopInput, Record<string, never>>('ipc:stop', ctx, {
229	        sessionId: created.sessionId,
230	      })
