1	#!/usr/bin/env node
2	import { randomUUID } from 'node:crypto';
3	import { pathToFileURL } from 'node:url';
4	import {
5	  query,
6	  type SDKAssistantMessage,
7	  type SDKUserMessage,
8	} from '@anthropic-ai/claude-agent-sdk';
9	import {
10	  createDiffAccumulator,
11	  createInboxLoop,
12	  createIpcClient,
13	  toWireChanges,
14	} from '@ax/agent-runner-core';
15	import type {
16	  ChatMessage,
17	  ContentBlock,
18	  ConversationFetchHistoryResponse,
19	  ConversationFetchHistoryTurn,
20	  ImageBlock,
21	  SessionGetConfigResponse,
22	  TextBlock,
23	  ToolListResponse,
24	  WorkspaceCommitNotifyResponse,
25	} from '@ax/ipc-protocol';
26	import { createCanUseTool } from './can-use-tool.js';
27	import { readRunnerEnv } from './env.js';
28	import { createHostMcpServer } from './host-mcp-server.js';
29	import { createPostToolUseHook } from './post-tool-use.js';
30	import { createPreToolUseHook } from './pre-tool-use.js';
31	import { DISABLED_BUILTINS, MCP_HOST_SERVER_NAME } from './tool-names.js';
32	
33	// ---------------------------------------------------------------------------
34	// Runner entry binary (claude-sdk variant).
35	//
36	// Spawned as a child process by a `sandbox:open-session` impl inside an
37	// isolated sandbox. Communicates back to the host over the URI in
38	// AX_RUNNER_ENDPOINT (unix:// today, http:// once Task 14 lands), authed
39	// with AX_AUTH_TOKEN.
40	//
41	// The runner holds NO LLM credentials (invariant I5). The vendored
42	// @anthropic-ai/claude-agent-sdk is redirected at our sandbox-internal LLM
43	// proxy via ANTHROPIC_BASE_URL; the proxy then calls host `llm.call` with
44	// the host-held key. If the sandbox is compromised, ANTHROPIC_API_KEY never
45	// entered this process.
46	//
47	// Shape: one persistent `query()` driven by an async generator that pulls
48	// user messages from the inbox long-poll. That keeps a single SDK session
49	// alive for the life of the runner instead of spawning a fresh one per
50	// chat turn — the SDK's internal conversation history carries across
51	// turns automatically.
52	//
53	// Exit codes (mirror @ax/agent-native-runner so the spawning host can
54	// branch identically regardless of runner flavor):
55	//   0 — chat completed normally (inbox returned cancel; SDK drained).
56	//   1 — terminated abnormally (SDK threw, IPC errored after retries, etc.).
57	//   2 — fatal during bootstrap (missing env, initial tool.list failure).
58	// ---------------------------------------------------------------------------
59	
60	export async function main(): Promise<number> {
61	  let env;
62	  try {
63	    env = readRunnerEnv();
64	  } catch (err) {
65	    process.stderr.write(
66	      `runner: ${err instanceof Error ? err.message : String(err)}\n`,
67	    );
68	    return 2;
69	  }
70	
71	  const client = createIpcClient({
72	    runnerEndpoint: env.runnerEndpoint,
73	    token: env.authToken,
74	  });
75	
76	  // Week 9.5: fetch the frozen agent config the orchestrator wrote when it
77	  // resolved this session's agent. We do this BEFORE tool.list so we can
78	  // filter the catalog defensively against `allowedTools` even if the
79	  // host's tool-dispatcher (Task 7) hasn't filtered yet.
80	  //
81	  // The bearer token in env.authToken is the SAME token the host used to
82	  // mint this session — the IPC server resolves it to ctx.sessionId, and
83	  // the session backend reads its own row keyed by that. There's no
84	  // sessionId on the wire; the runner cannot ask for someone else's
85	  // config.
86	  let agentConfig: SessionGetConfigResponse['agentConfig'];
87	  let conversationId: string | null = null;
88	  try {
89	    const cfg = (await client.call(
90	      'session.get-config',
91	      {},
92	    )) as SessionGetConfigResponse;
93	    agentConfig = cfg.agentConfig;
94	    // Task 15 (Week 10–12): the host populates conversationId at session-
95	    // creation time when the runner is for an existing conversation. The
96	    // runner uses a truthy value as the trigger to fetch transcript
97	    // history and replay it into the SDK's prompt iterator (J3 + J6
98	    // resume). We normalize `undefined` (older host that hasn't shipped
99	    // the field) and `null` (non-conversation session) into the same
100	    // skip-replay branch via a strict equality check on the string type
101	    // — anything else takes the fetch path.
102	    conversationId = typeof cfg.conversationId === 'string' ? cfg.conversationId : null;
103	  } catch (err) {
104	    process.stderr.write(
105	      `runner: session.get-config failed: ${err instanceof Error ? err.message : String(err)}\n`,
106	    );
107	    await client.close();
108	    return 2;
109	  }
110	
111	  // Task 15 (Week 10–12): replay-at-boot. Fetch the persisted transcript
112	  // BEFORE constructing the SDK iterator so the model sees prior turns
113	  // before any live inbox message.
114	  //
115	  // Failure semantics: NON-FATAL. A storage hiccup or ACL drift here
116	  // shouldn't kill the chat — we'd rather hand the user a fresh
117	  // conversation than crash on resume. We log to stderr and continue
118	  // with an empty history.
119	  //
120	  // What we replay (and what we DON'T):
121	  //   - User turns and tool turns (tool_result blocks): yielded as
122	  //     SDKUserMessage. The SDK accepts a user message whose content is
123	  //     either a string or an Anthropic-compatible content-block array;
124	  //     we use the array form so tool_result blocks round-trip.
125	  //   - Assistant turns: NOT re-yielded. The SDK's prompt iterator only
126	  //     accepts user-shaped messages; injecting prior assistant text
127	  //     would require either the SDK's `resume(sessionId)` (we don't
128	  //     track its internal session id across runner restarts) or a
129	  //     `setMessages` API that doesn't exist today. The model regenerates
130	  //     from the user-side context. This re-spends LLM tokens but is
131	  //     simple and correct — the model has full context for a coherent
132	  //     continuation. (Future optimization: pursue resume(sessionId).)
133	  let replayTurns: ConversationFetchHistoryTurn[] = [];
134	  if (conversationId !== null) {
135	    try {
136	      const resp = (await client.call('conversation.fetch-history', {
137	        conversationId,
138	      })) as ConversationFetchHistoryResponse;
139	      replayTurns = resp.turns;
140	    } catch (err) {
141	      process.stderr.write(
142	        `runner: conversation.fetch-history failed: ${err instanceof Error ? err.message : String(err)}\n`,
143	      );
144	      replayTurns = [];
145	    }
146	  }
147	
148	  let tools;
149	  try {
150	    tools = ((await client.call('tool.list', {})) as ToolListResponse).tools;
151	  } catch (err) {
152	    process.stderr.write(
153	      `runner: tool.list failed: ${err instanceof Error ? err.message : String(err)}\n`,
154	    );
155	    await client.close();
156	    return 2;
157	  }
158	
159	  // Defensive client-side filter against agentConfig.allowedTools when it
160	  // is non-empty. An empty allow-list means "no per-agent restriction"
161	  // (orchestrator default); a non-empty list overrides what the host
162	  // returned. This is belt-and-suspenders against the dispatcher filter
163	  // (Task 7) — if either the host or runner mis-orders a refactor, the
164	  // tool catalog the SDK sees is still bounded.
165	  if (agentConfig.allowedTools.length > 0) {
166	    const allow = new Set(agentConfig.allowedTools);
167	    tools = tools.filter((t) => allow.has(t.name));
168	  }
169	
170	  const hostMcpServer = createHostMcpServer({ client, tools });
171	  const inbox = createInboxLoop({ client });
172	  // Per-turn diff accumulator (Task 7c). PostToolUse populates; the
173	  // `result` SDK message drains and ships a single `workspace.commit-
174	  // notify`. Workspace commits are turn-end, NOT per-tool-call.
175	  const diffs = createDiffAccumulator();
176	  // Tracks the last accepted workspace version so the host's optimistic-
177	  // concurrency check sees a coherent lineage across turns.
178	  let parentVersion: string | null = null;
179	  // Host-side bookkeeping for the final event.chat-end outcome. The SDK
180	  // maintains its OWN transcript internally; this array is only the shape
181	  // the host cares about (user/assistant text round-tripped through
182	  // ChatMessage). NOT the same as `replayTurns` above — replayTurns is
183	  // the persisted history we pull at boot to seed the SDK; chatEndHistory
184	  // is the within-process trace the host gets at chat:end.
185	  const chatEndHistory: ChatMessage[] = [];
186	
187	  // Per-turn content-block accumulators. Drained at the SDK `result`
188	  // boundary into event.turn-end so @ax/conversations can persist the
189	  // turn (Task 3 of Week 10–12). We track assistant and tool turns
190	  // separately because they emit as distinct chat:turn-end events:
191	  //   - assistant: text + thinking + tool_use blocks observed in
192	  //     `assistant` SDK messages within the current turn.
193	  //   - tool: tool_result blocks observed in `user` SDK messages whose
194	  //     content is the SDK echoing the tool-result back into the
195	  //     transcript. Replay (Task 15) needs these to reconstruct the
196	  //     conversation; the user-side text the human typed already
197	  //     reaches the conversation table via POST /api/chat/messages
198	  //     (Task 9), so we deliberately skip plain-text user blocks here.
199	  let turnContentBlocks: ContentBlock[] = [];
200	  let turnToolResultBlocks: ContentBlock[] = [];
201	
202	  // Most-recent host-minted reqId from the inbox (J9). Set when a user
203	  // message arrives; read by `event.stream-chunk` emissions during the
204	  // assistant branch below. Lifetime is "from the inbox pull until the
205	  // next inbox pull" — chunks for the SAME reqId may continue across
206	  // multiple SDK `result` boundaries (the SDK may break a long response
207	  // into multiple turns), so we DO NOT clear this on turn-end. A chunk
208	  // that would emit before any user message has been pulled is impossible
209	  // by SDK construction (no input → no output), but we defend anyway:
210	  // an unset reqId causes the chunk to be skipped (no `event.stream-chunk`
211	  // with a missing reqId — the host's router can't route it).
212	  let currentReqId: string | undefined;
213	
214	  // Inbox → SDK user-message generator. Closing via `return` on cancel
215	  // tells the SDK no more user messages are coming, which lets the outer
216	  // `for await (msg of queryIter)` drain naturally and exit.
217	  //
218	  // Task 15 (Week 10–12): replay-at-boot. We yield prior user turns
219	  // (role=user with text content) BEFORE pulling from the live inbox.
220	  // Assistant AND tool turns are skipped — the model regenerates the
221	  // tool flow from the user-side context. We can't re-yield tool turns
222	  // standalone: Anthropic's API rejects (400 invalid_request_error) any
223	  // tool_result block that isn't paired with a tool_use in the
224	  // immediately preceding assistant message, and we don't have the
225	  // assistant turn (since the prompt iterator only accepts user-shaped
226	  // messages). Without the SDK's resume() API, replaying tool turns is
227	  // not safely possible. The conversation row still stores the tool
228	  // turn (Task 3's auto-append); on replay the SDK only sees user text
229	  // turns and the model regenerates tool flows from there.
230	  async function* userMessages(): AsyncGenerator<SDKUserMessage> {
231	    // ----- replay -----
232	    for (const turn of replayTurns) {
233	      if (turn.role === 'user') {
234	        // Collapse plain-text contentBlocks back into a string for the
235	        // SDK (matches the live-inbox shape so the model doesn't see a
236	        // mid-conversation format change). Multi-block user turns
237	        // (e.g. with images) yield the full block array.
238	        const allText = turn.contentBlocks.every(
239	          (b): b is TextBlock => b.type === 'text',
240	        );
241	        const content: SDKUserMessage['message']['content'] = allText
242	          ? turn.contentBlocks
243	              .map((b) => (b as TextBlock).text)
244	              .join('\n')
245	          : (turn.contentBlocks as unknown as SDKUserMessage['message']['content']);
246	        yield {
247	          type: 'user',
248	          parent_tool_use_id: null,
249	          message: { role: 'user', content },
250	        };
251	      } else {
252	        // assistant + tool turns are NOT re-yielded; the model
253	        // regenerates from the user-side context. Tool turns
254	        // specifically can't be yielded standalone (Anthropic 400:
255	        // tool_result without paired tool_use in the immediately
256	        // preceding assistant message).
257	        process.stderr.write(
258	          `runner: skipping replay of role=${turn.role} turn (model will regenerate from user-side context)\n`,
259	        );
260	      }
261	    }
262	    // ----- live inbox -----
263	    for (;;) {
264	      const entry = await inbox.next();
265	      if (entry.type === 'cancel') return;
266	      if (entry.payload === undefined) continue;
267	      // Capture the host-minted reqId so subsequent stream-chunk
268	      // emissions correlate back to the originating request. Both fields
269	      // are set on `user-message` entries by the InboxLoop layer.
270	      if (typeof entry.reqId === 'string' && entry.reqId.length > 0) {
271	        currentReqId = entry.reqId;
272	      }
273	      chatEndHistory.push({ role: 'user', content: entry.payload.content });
274	      yield {
275	        type: 'user',
276	        parent_tool_use_id: null,
277	        message: { role: 'user', content: entry.payload.content },
278	      };
279	    }
280	  }
281	
282	  let exitCode = 0;
283	  let terminatedReason: string | undefined;
284	  let terminatedError:
285	    | { name: string; message: string; stack?: string }
286	    | undefined;
287	
288	  try {
289	    const queryIter = query({
290	      prompt: userMessages(),
291	      options: {
292	        // Route the SDK's Anthropic calls through our in-sandbox proxy so
293	        // the real API key stays host-side. The auth token here is the
294	        // sandbox's IPC bearer — the proxy validates it before forwarding.
295	        env: {
296	          ANTHROPIC_BASE_URL: env.llmProxyUrl,
297	          ANTHROPIC_API_KEY: env.authToken,
298	        },
299	        cwd: env.workspaceRoot,
300	        disallowedTools: [...DISABLED_BUILTINS],
301	        // canUseTool stays as a belt-and-suspenders allow-path. The real
302	        // pre-call hook-bus forwarding happens in the PreToolUse hook below,
303	        // which ALWAYS fires (canUseTool only fires when the CLI decides a
304	        // tool needs a permission prompt — built-ins like Bash with benign
305	        // input don't reach it). See pre-tool-use.ts for the rationale.
306	        canUseTool: createCanUseTool({ client }),
307	        hooks: {
308	          PreToolUse: [{ hooks: [createPreToolUseHook({ client })] }],
309	          PostToolUse: [
310	            {
311	              hooks: [
312	                createPostToolUseHook({
313	                  client,
314	                  diffs,
315	                  workspaceRoot: env.workspaceRoot,
316	                }),
317	              ],
318	            },
319	          ],
320	        },
321	        mcpServers: { [MCP_HOST_SERVER_NAME]: hostMcpServer },
322	        // Empty settingSources = SDK isolation mode: the runner does NOT
323	        // read ~/.claude, project settings, or CLAUDE.md. Config for this
324	        // sandbox arrives entirely through host-mediated IPC.
325	        settingSources: [],
326	        // Week 9.5: use the frozen agentConfig.systemPrompt the host wrote
327	        // at session-creation time. An empty string falls back to the SDK
328	        // preset (the dev-agents-stub seeds a default; production agents
329	        // require non-empty by validation). systemPrompt is USER-AUTHORED
330	        // and intended for the LLM — not interpolated into shell, paths,
331	        // or HTML.
332	        systemPrompt:
333	          agentConfig.systemPrompt.length > 0
334	            ? agentConfig.systemPrompt
335	            : { type: 'preset', preset: 'claude_code' },
336	      },
337	    });
338	
339	    for await (const msg of queryIter) {
340	      if (msg.type === 'assistant') {
341	        const assistant: SDKAssistantMessage = msg;
342	        // Only plain text blocks round-trip into host history. Tool-use
343	        // blocks stay inside the SDK's session — the host observes tool
344	        // activity via event.tool-post-call, not via the transcript.
345	        const text = assistant.message.content
346	          .flatMap((block) => (block.type === 'text' ? [block.text] : []))
347	          .join('\n');
348	        if (text.length > 0) {
349	          chatEndHistory.push({ role: 'assistant', content: text });
350	        }
351	        // Accumulate full ContentBlock[] for the per-turn transcript that
352	        // ships to @ax/conversations via event.turn-end. Every block kind
353	        // ContentBlockSchema knows about is mapped explicitly:
354	        //   - text / thinking / redacted_thinking / tool_use
355	        //
356	        // Replay (Task 15) requires Anthropic-compatibility (J3): a
357	        // missing redacted_thinking block leaves a hole the model can
358	        // detect on a follow-up turn, so we MUST preserve it verbatim.
359	        // Unknown block kinds are dropped defensively so a future SDK
360	        // addition can't bypass the canonical schema.
361	        for (const block of assistant.message.content) {
362	          if (block.type === 'text') {
363	            turnContentBlocks.push({ type: 'text', text: block.text });
364	            // Per-block streaming (Task 6 / J9). The SDK delivers text
365	            // blocks as the model produces them; we forward each as a
366	            // `event.stream-chunk` so the host's chat:stream-chunk
367	            // subscriber (Task 5) can fan out to waiting clients (Task
368	            // 7). Empty-text blocks are skipped — emitting `{ text: '' }`
369	            // chunks is noise. Failure is non-fatal: the host may be
370	            // tearing down, and the canonical transcript still flows
371	            // via event.turn-end / event.chat-end. Untrusted (J2):
372	            // `block.text` is model output and reaches the host
373	            // verbatim — host-side renderers sanitize.
374	            if (currentReqId !== undefined && block.text.length > 0) {
375	              await client
376	                .event('event.stream-chunk', {
377	                  reqId: currentReqId,
378	                  text: block.text,
379	                  kind: 'text',
380	                })
381	                .catch(() => {
382	                  /* host may be tearing down; non-fatal */
383	                });
384	            }
385	          } else if (block.type === 'thinking') {
386	            turnContentBlocks.push({
387	              type: 'thinking',
388	              thinking: block.thinking,
389	              ...(typeof block.signature === 'string'
390	                ? { signature: block.signature }
391	                : {}),
392	            });
393	            // Same per-block streaming for thinking. The host's UI
394	            // toggles thinking visibility (Task 21 / J4), but the
395	            // chunk still travels with `kind: 'thinking'` so a
396	            // subscriber can route it to the right pane.
397	            if (currentReqId !== undefined && block.thinking.length > 0) {
398	              await client
399	                .event('event.stream-chunk', {
400	                  reqId: currentReqId,
401	                  text: block.thinking,
402	                  kind: 'thinking',
403	                })
404	                .catch(() => {
405	                  /* host may be tearing down; non-fatal */
406	                });
407	            }
408	          } else if (block.type === 'redacted_thinking') {
409	            // Redacted-thinking blocks have no human-readable text — the
410	            // model returned an opaque blob. We persist it (J3 — the
411	            // SDK detects holes on follow-up turns) but DO NOT emit a
412	            // stream chunk: there's nothing to render, and `kind`
413	            // wouldn't accept it anyway.
414	            turnContentBlocks.push({
415	              type: 'redacted_thinking',
416	              data: (block as { data: string }).data,
417	            });
418	          } else if (block.type === 'tool_use') {
419	            // Tool-use blocks are observed via event.tool-post-call
420	            // (when the tool actually runs) and persisted at turn-end.
421	            // They are not streamed text and have no `kind` mapping.
422	            turnContentBlocks.push({
423	              type: 'tool_use',
424	              id: block.id,
425	              name: block.name,
426	              input: (block.input ?? {}) as Record<string, unknown>,
427	            });
428	          }
429	        }
430	      } else if (msg.type === 'user') {
431	        // The SDK echoes tool_result blocks back as `user` messages once
432	        // a tool finishes (the model issued a tool_use; the runner ran
433	        // the tool; the SDK threads the result into the transcript as a
434	        // user turn so the next assistant turn can see it). Replay
435	        // depends on these landing in the conversation row. Plain-text
436	        // user content is NOT collected: the human's typed message
437	        // arrives via POST /api/chat/messages (Task 9), and tool_result
438	        // blocks are the only thing the runner is the authoritative
439	        // source for here.
440	        const userMsg = msg as { message?: { content?: unknown } };
441	        const content = userMsg.message?.content;
442	        if (Array.isArray(content)) {
443	          for (const block of content as Array<{ type?: string }>) {
444	            if (block.type === 'tool_result') {
445	              const tr = block as {
446	                type: 'tool_result';
447	                tool_use_id?: string;
448	                content?: unknown;
449	                is_error?: boolean;
450	              };
451	              if (typeof tr.tool_use_id === 'string') {
452	                // Narrow array content to the text/image subset per
453	                // ToolResultBlockSchema (`string | (TextBlock |
454	                // ImageBlock)[]`). Image entries MUST round-trip — a
455	                // tool that returns image content (screenshot tool, Read
456	                // on a binary, etc.) loses context on replay otherwise.
457	                // Other entry types are dropped defensively so a future
458	                // SDK shape doesn't silently bypass the canonical schema.
459	                let normalizedContent: string | Array<TextBlock | ImageBlock> =
460	                  '';
461	                if (typeof tr.content === 'string') {
462	                  normalizedContent = tr.content;
463	                } else if (Array.isArray(tr.content)) {
464	                  const narrowed: Array<TextBlock | ImageBlock> = [];
465	                  for (const item of tr.content as Array<{
466	                    type?: string;
467	                    text?: unknown;
468	                    source?: unknown;
469	                  }>) {
470	                    if (item.type === 'text' && typeof item.text === 'string') {
471	                      narrowed.push({ type: 'text', text: item.text });
472	                    } else if (
473	                      item.type === 'image' &&
474	                      item.source !== undefined
475	                    ) {
476	                      // The SDK's image-block shape matches ImageBlock
477	                      // already; the .source discriminated-union is
478	                      // validated at the storage boundary by
479	                      // ContentBlockSchema, so no further narrowing here.
480	                      narrowed.push(item as unknown as ImageBlock);
481	                    }
482	                  }
483	                  normalizedContent = narrowed;
484	                }
485	                const normalized: ContentBlock = {
486	                  type: 'tool_result',
487	                  tool_use_id: tr.tool_use_id,
488	                  content: normalizedContent,
489	                  ...(typeof tr.is_error === 'boolean'
490	                    ? { is_error: tr.is_error }
491	                    : {}),
492	                };
493	                turnToolResultBlocks.push(normalized);
494	              }
495	            }
496	          }
497	        }
498	      } else if (msg.type === 'result') {
499	        // Turn boundary. Snapshot the per-turn diff accumulator and ship
500	        // a single `workspace.commit-notify` when there are changes. We
501	        // skip empty turns deliberately: a host with no workspace plugin
502	        // registered would log an internal error on each empty notify,
503	        // and `event.turn-end` already carries the heartbeat signal.
504	        // Failures here MUST NOT terminate the chat.
505	        //
506	        // Snapshot-then-drain-on-receipt: on thrown errors the
507	        // accumulator stays intact so the next turn retries the same
508	        // changes plus whatever new ones land — no silent data loss on
509	        // transient network/timeout failures. On host `accepted: false`
510	        // we drain anyway: re-sending against the same stale parent
511	        // fails forever, and the proper "refresh parent on mismatch"
512	        // flow needs a wire change out of scope here. Same trade-off
513	        // the native runner makes; both paths share `DiffAccumulator`.
514	        if (!diffs.isEmpty()) {
515	          const snapshot = diffs.snapshot();
516	          try {
517	            const resp = (await client.call('workspace.commit-notify', {
518	              parentVersion,
519	              commitRef: randomUUID(),
520	              message: 'turn',
521	              changes: toWireChanges(snapshot),
522	            })) as WorkspaceCommitNotifyResponse;
523	            if (resp.accepted) {
524	              diffs.drain();
525	              parentVersion = resp.version as unknown as string;
526	            } else {
527	              diffs.drain();
528	            }
529	          } catch {
530	            /* preserve accumulator; next turn retries */
531	          }
532	        }
533	
534	        // One turn of assistant output finished. The SDK now awaits the
535	        // next yield from userMessages() — i.e. the next inbox pull.
536	        //
537	        // We may emit up to TWO chat:turn-end events at this boundary:
538	        //   1. role='tool' if the runner observed any tool_result blocks
539	        //      during this turn (the SDK echoed them back as user msgs).
540	        //      Emitted FIRST because they chronologically precede the
541	        //      assistant's wrap-up text in the transcript.
542	        //   2. role='assistant' for the assistant turn itself. Emitted
543	        //      unconditionally as a heartbeat — contentBlocks is only
544	        //      attached when non-empty so empty turns stay heartbeats.
545	        //
546	        // Failures here MUST NOT terminate the chat (host may be tearing
547	        // down). Each call swallows independently.
548	        if (turnToolResultBlocks.length > 0) {
549	          const toolBlocks = turnToolResultBlocks;
550	          turnToolResultBlocks = [];
551	          await client
552	            .event('event.turn-end', {
553	              reason: 'user-message-wait',
554	              role: 'tool',
555	              contentBlocks: toolBlocks,
556	            })
557	            .catch(() => {
558	              /* host may be tearing down; non-fatal */
559	            });
560	        }
561	
562	        const assistantBlocks = turnContentBlocks;
563	        turnContentBlocks = [];
564	        await client
565	          .event('event.turn-end', {
566	            reason: 'user-message-wait',
567	            role: 'assistant',
568	            ...(assistantBlocks.length > 0
569	              ? { contentBlocks: assistantBlocks }
570	              : {}),
571	          })
572	          .catch(() => {
573	            /* host may be tearing down; non-fatal */
574	          });
575	      }
576	      // system / partial / progress / etc. are SDK bookkeeping —
577	      // the host doesn't need to see them. (`user` messages ARE handled
578	      // above, but only to extract tool_result blocks for replay.)
579	    }
580	  } catch (err) {
581	    exitCode = 1;
582	    if (err instanceof Error) {
583	      terminatedReason = `${err.name}: ${err.message}`;
584	      terminatedError = {
585	        name: err.name,
586	        message: err.message,
587	        ...(err.stack !== undefined ? { stack: err.stack } : {}),
588	      };
589	    } else {
590	      terminatedReason = String(err);
591	      terminatedError = { name: 'NonError', message: String(err) };
592	    }
593	  }
594	
595	  // Single event.chat-end at the end of the runner's life, awaited so the
596	  // event reaches the wire before the process exits. If the host is
597	  // already gone, swallow — there's nothing left to signal to. The
598	  // `error` shape here is a plain object so the event payload survives
599	  // JSON.stringify (an `Error` instance would serialize to `{}`, stripping
600	  // the diagnostic).
601	  const outcome =
602	    exitCode === 0
603	      ? { kind: 'complete' as const, messages: chatEndHistory }
604	      : {
605	          kind: 'terminated' as const,
606	          reason: terminatedReason ?? 'unknown',
607	          ...(terminatedError !== undefined ? { error: terminatedError } : {}),
608	        };
609	  await client.event('event.chat-end', { outcome }).catch(() => {
610	    /* swallow */
611	  });
612	  await client.close().catch(() => {
613	    /* close is best-effort; a clean chat shouldn't exit non-zero on teardown */
614	  });
615	  return exitCode;
616	}
617	
618	// ESM main-module guard. `require.main === module` doesn't work in ESM.
619	// Compare URLs to detect "was this file invoked directly".
620	if (
621	  process.argv[1] !== undefined &&
622	  import.meta.url === pathToFileURL(process.argv[1]).href
623	) {
624	  main()
625	    .then((code) => process.exit(code))
626	    .catch((err: unknown) => {
627	      process.stderr.write(
628	        `runner: fatal: ${err instanceof Error ? err.message : String(err)}\n`,
629	      );
630	      process.exit(2);
631	    });
632	}
