64	/**
65	 * Default location of the claude-sdk runner binary. Resolved against the
66	 * preset's own URL so pnpm hoisting and prod/dev installs both work.
67	 */
68	function defaultRunnerBinary(): string {
69	  return requireFromPreset.resolve('@ax/agent-claude-sdk-runner');
70	}
