105	/**
106	 * Discriminated union for the workspace backend. `local` keeps the
107	 * single-replica on-PVC bare repo path; `http` forwards every workspace op to
108	 * the shared git-server pod so multiple host replicas can share state.
109	 */
110	export type K8sWorkspaceConfig =
111	  | { backend: 'local'; repoRoot: string }
112	  | { backend: 'http'; baseUrl: string; token: string };
113	
114	export interface K8sPresetConfig {
115	  /**
116	   * Postgres pool config used by @ax/database-postgres + @ax/storage-postgres.
117	   * (Storage doesn't take its own connection — it reaches the shared pool
118	   * via `database:get-instance`.)
119	   */
120	  database: {
121	    connectionString: string;
122	    poolMax?: number;
123	  };
124	  /**
125	   * Eventbus opens its OWN dedicated pg.Client for LISTEN/NOTIFY — pooled
126	   * connections can't hold a LISTEN binding through idle returns. So this
127	   * is intentionally a separate connectionString (typically the same DSN).
128	   */
129	  eventbus: {
130	    connectionString: string;
131	  };
132	  /**
133	   * Same deal: session-postgres opens its own pool + listen client because
134	   * inbox claim-work blocks on LISTEN. Configured separately.
135	   */
136	  session: {
137	    connectionString: string;
138	    poolMax?: number;
139	  };
140	  /**
141	   * Workspace backend selection. Two flavors:
142	   *
143	   *   - `local`: `@ax/workspace-git` writes a bare repo on the host pod's PVC.
144	   *     Single-replica deploys only — two hosts mounting the same RWO PVC
145	   *     would race. `repoRoot` is the directory hosting `<repoRoot>/repo.git`;
146	   *     the plugin idempotently `git init`s it on first use.
147	   *
148	   *   - `http`: `@ax/workspace-git-http` forwards every workspace op to the
149	   *     dedicated git-server pod over HTTP. Multi-replica capable. `baseUrl`
150	   *     points at the git-server's cluster Service; `token` is the shared
151	   *     bearer token (via Helm-managed Secret).
152	   *
153	   * The Helm chart drives this via `workspace.backend: local|http` and the
154	   * env vars `AX_WORKSPACE_BACKEND` / `AX_WORKSPACE_ROOT` /
155	   * `AX_WORKSPACE_GIT_HTTP_URL` / `AX_WORKSPACE_GIT_HTTP_TOKEN`. The host
156	   * entrypoint reads those and constructs this config.
157	   */
158	  workspace: K8sWorkspaceConfig;
159	  /**
160	   * Pod template + readiness/limits config for sandbox-k8s. All fields
161	   * optional; defaults live in @ax/sandbox-k8s/src/config.ts.
162	   */
163	  sandbox?: {
164	    namespace?: string;
165	    image?: string;
166	    runtimeClassName?: string;
167	    imagePullSecrets?: string[];
168	    cpuLimit?: string;
169	    memoryLimit?: string;
170	    cpuRequest?: string;
171	    memoryRequest?: string;
172	    activeDeadlineSeconds?: number;
173	    readinessPollMs?: number;
174	    readinessTimeoutMs?: number;
175	  };
176	  /**
