208	    runnerBinary?: string;
209	    chatTimeoutMs?: number;
210	    oneShot?: boolean;
211	  };
212	  /**
213	   * @ax/http-server config. The host listener that serves /admin/*, /auth/*,
214	   * /admin/me, /admin/sign-out, and (Week 10-12) the admin UI. Distinct from
215	   * the @ax/ipc-http listener above — that one is the runner-pod ↔ host
216	   * back-channel and never faces public traffic.
217	   *
218	   * `cookieKey` accepts either 64 hex chars or 44 base64 chars (32-byte key).
219	   * It's parsed by the preset and handed to the plugin as a Buffer. We
220	   * deliberately keep the string form on the preset config so the type is
221	   * JSON-serializable for the chart's ConfigMap path.
222	   *
223	   * `allowedOrigins` is the exact-match CSRF allow-list for state-changing
224	   * methods. The admin UI's origin (Week 10-12) lands here; for now the
225	   * chart provides whatever the operator sets via env.
226	   */
227	  http: {
228	    /** Bind address. Default '0.0.0.0' for in-cluster; '127.0.0.1' for tests. */
229	    host: string;
230	    /** Bind port. Pass 0 for OS-assigned (tests). */
231	    port: number;
232	    /** 32-byte signing key as 64 hex chars or 44 base64 chars. */
233	    cookieKey: string;
234	    /** Exact-match CSRF allow-list. Empty allows only X-Requested-With callers. */
235	    allowedOrigins: string[];
236	  };
237	  /**
238	   * @ax/auth config. At least one of `google` (OIDC) or `devBootstrap`
239	   * MUST be set; the plugin throws `no-auth-providers` otherwise.
240	   *
241	   * Production deploys typically set `google` only. Dev / canary / kind
242	   * deploys set `devBootstrap` only. Both can coexist for staging-like
243	   * environments — the auth plugin won't refuse it.
244	   */
245	  auth: {
246	    google?: {
247	      clientId: string;
248	      clientSecret: string;
249	      issuer: string;
250	      redirectUri: string;
251	    };
