258	    /** Session cookie lifetime. Default 7 days (in @ax/auth). */
259	    sessionLifetimeSeconds?: number;
260	  };
261	  /**
262	   * Optional static-file serving (production single-binary mode). When
263	   * set, mounts `@ax/static-files` after the API routes so it serves
264	   * channel-web's bundle on otherwise-unmatched paths. SPA fallback
265	   * defaults to `true` (returns `index.html` for unknown paths so
266	   * client-side routing works). Leave unset for dev — Vite handles
267	   * static + proxy in dev.
268	   */
269	  staticFiles?: {
270	    /** Absolute path to the directory to serve (e.g., channel-web/dist). */
271	    dir: string;
272	    /** URL pattern, defaults to `/*`. */
273	    mountPath?: string;
274	    /**
275	     * SPA fallback (default `true` = serve `index.html` on miss).
276	     * Pass a string to use a different fallback file; pass `false`
277	     * to return 404 on miss.
278	     */
279	    spaFallback?: boolean | string;
280	  };
281	}
