283	/**
284	 * Build the production plugin list for k8s mode. Pass the result straight to
285	 * `bootstrap({ bus, plugins, config: {} })` from @ax/core.
286	 *
287	 * Note: the runner binary resolution and Anthropic API key both rely on
288	 * runtime environment (the binary lookup walks node_modules, the API key
289	 * comes from process.env). That's intentional — secrets and resolved paths
290	 * are not in the JSON config schema.
291	 */
292	export function createK8sPlugins(config: K8sPresetConfig): Plugin[] {
293	  const plugins: Plugin[] = [];
294	
295	  // ----- 1. stateful base layer ------------------------------------------
296	  // database-postgres owns the shared pg.Pool. storage-postgres reaches it
297	  // via `database:get-instance` (not a direct import — invariant I2).
298	  plugins.push(
299	    createDatabasePostgresPlugin({
300	      connectionString: config.database.connectionString,
301	      ...(config.database.poolMax !== undefined
302	        ? { poolMax: config.database.poolMax }
303	        : {}),
304	    }),
305	  );
306	  plugins.push(createStoragePostgresPlugin());
307	
308	  // Credentials: facade over the storage-blob seam. The default backend
309	  // (@ax/credentials-store-db) wraps storage:get/storage:set with the
310	  // `credential:` key prefix; the facade owns AES-256-GCM and the
311	  // consumer-facing credentials:get/set/delete contract. Init throws if
312	  // AX_CREDENTIALS_KEY isn't in env.
313	  plugins.push(createCredentialsStoreDbPlugin());
314	  plugins.push(createCredentialsPlugin());
315	
316	  // ----- 2. cross-process coordination ----------------------------------
317	  // Eventbus and session each own a dedicated LISTEN client.
318	  plugins.push(
319	    createEventbusPostgresPlugin({
320	      connectionString: config.eventbus.connectionString,
321	    }),
322	  );
323	  plugins.push(
324	    createSessionPostgresPlugin({
325	      connectionString: config.session.connectionString,
326	      ...(config.session.poolMax !== undefined
327	        ? { poolMax: config.session.poolMax }
328	        : {}),
329	    }),
330	  );
331	
332	  // ----- 3. workspace ----------------------------------------------------
333	  // Discriminated on `backend`. The shape difference is intentional: `local`
334	  // wants a filesystem path, `http` wants a URL + bearer token. Both register
335	  // the same four `workspace:*` service hooks (Invariant I1 — the contract is
336	  // the same regardless of backend).
337	  if (config.workspace.backend === 'http') {
338	    plugins.push(
339	      createWorkspaceGitHttpPlugin({
340	        baseUrl: config.workspace.baseUrl,
341	        token: config.workspace.token,
342	      }),
343	    );
344	  } else {
345	    plugins.push(
346	      createWorkspaceGitPlugin({
347	        repoRoot: config.workspace.repoRoot,
348	      }),
349	    );
350	  }
351	
352	  // ----- 4. audit log ----------------------------------------------------
353	  // Subscribes to chat:end and writes a record via storage:set. Pushed
354	  // before the chat-orchestrator so its subscription is in place when the
355	  // first chat:end fires.
356	  plugins.push(auditLogPlugin());
357	
358	  // ----- 5. control-plane access (Week 9.5) -----------------------------
359	  // http-server provides the public-facing listener. auth registers the
360	  // /auth/* + /admin/{me,sign-out} routes and the auth:require-user gate
361	  // every admin endpoint depends on. teams owns /admin/teams* and the
362	  // teams:* hooks the agents-plugin's team-visibility ACL calls.
363	  //
364	  // Boot order: the kernel topologically sorts on `manifest.calls`
365	  // (http:register-route → @ax/http-server, auth:require-user → @ax/auth),
366	  // so even if we shuffled the array the kernel would init http-server
367	  // before auth before agents/teams. We push in the conceptual order to
368	  // keep the intent legible to readers.
369	  plugins.push(
370	    createHttpServerPlugin({
371	      host: config.http.host,
372	      port: config.http.port,
373	      cookieKey: parseCookieKeyString(config.http.cookieKey),
374	      allowedOrigins: config.http.allowedOrigins,
375	    }),
376	  );
377	
378	  const authConfig: AuthConfig = { providers: {} };
379	  if (config.auth.google !== undefined) {
380	    authConfig.providers.google = {
381	      clientId: config.auth.google.clientId,
382	      clientSecret: config.auth.google.clientSecret,
383	      issuer: config.auth.google.issuer,
384	      redirectUri: config.auth.google.redirectUri,
385	    };
386	  }
387	  if (config.auth.devBootstrap !== undefined) {
388	    authConfig.devBootstrap = { token: config.auth.devBootstrap.token };
389	  }
390	  if (config.auth.sessionLifetimeSeconds !== undefined) {
391	    authConfig.sessionLifetimeSeconds = config.auth.sessionLifetimeSeconds;
392	  }
393	  plugins.push(createAuthPlugin(authConfig));
394	
395	  // teams: mountAdminRoutes:true so /admin/teams* lands alongside the rest
396	  // of the admin surface. The plugin's manifest expands `calls` to include
397	  // http:register-route + auth:require-user when this flag is set, which
398	  // is exactly what the kernel's topo-sort needs to see.
399	  plugins.push(createTeamsPlugin({ mountAdminRoutes: true }));
400	
401	  // static-files (optional): serves channel-web's bundle from the same
402	  // listener so cookies and CSRF stay same-origin in production. The
403	  // plugin registers a `/*` catchall LAST so every API route registered
404	  // earlier wins. When `staticFiles` is unset, no catchall is mounted
405	  // and unknown paths return 404 — the dev workflow uses Vite's proxy
406	  // instead. SPA fallback defaults on so client-side routing works.
407	  if (config.staticFiles !== undefined) {
408	    plugins.push(
409	      createStaticFilesPlugin({
410	        dir: config.staticFiles.dir,
411	        ...(config.staticFiles.mountPath !== undefined
412	          ? { mountPath: config.staticFiles.mountPath }
413	          : {}),
414	        spaFallback: config.staticFiles.spaFallback ?? true,
415	      }),
416	    );
417	  }
418	
419	  // ----- 6. chat plane ---------------------------------------------------
420	  // sandbox-k8s registers `sandbox:open-session`. No subprocess fallback
421	  // here — this preset is k8s-only.
422	  const sandboxOpts = {
423	    hostIpcUrl: config.ipc.hostIpcUrl,
424	    ...(config.sandbox?.namespace !== undefined
425	      ? { namespace: config.sandbox.namespace }
426	      : {}),
427	    ...(config.sandbox?.image !== undefined
428	      ? { image: config.sandbox.image }
429	      : {}),
430	    ...(config.sandbox?.runtimeClassName !== undefined
431	      ? { runtimeClassName: config.sandbox.runtimeClassName }
432	      : {}),
433	    ...(config.sandbox?.imagePullSecrets !== undefined
434	      ? { imagePullSecrets: config.sandbox.imagePullSecrets }
435	      : {}),
436	    ...(config.sandbox?.cpuLimit !== undefined
437	      ? { cpuLimit: config.sandbox.cpuLimit }
438	      : {}),
439	    ...(config.sandbox?.memoryLimit !== undefined
440	      ? { memoryLimit: config.sandbox.memoryLimit }
441	      : {}),
442	    ...(config.sandbox?.cpuRequest !== undefined
443	      ? { cpuRequest: config.sandbox.cpuRequest }
444	      : {}),
445	    ...(config.sandbox?.memoryRequest !== undefined
446	      ? { memoryRequest: config.sandbox.memoryRequest }
447	      : {}),
448	    ...(config.sandbox?.activeDeadlineSeconds !== undefined
449	      ? { activeDeadlineSeconds: config.sandbox.activeDeadlineSeconds }
450	      : {}),
451	    ...(config.sandbox?.readinessPollMs !== undefined
452	      ? { readinessPollMs: config.sandbox.readinessPollMs }
453	      : {}),
454	    ...(config.sandbox?.readinessTimeoutMs !== undefined
455	      ? { readinessTimeoutMs: config.sandbox.readinessTimeoutMs }
456	      : {}),
457	  };
458	  plugins.push(createSandboxK8sPlugin(sandboxOpts));
459	
460	  plugins.push(
461	    createIpcHttpPlugin({
462	      host: config.ipc.host ?? '0.0.0.0',
463	      port: config.ipc.port ?? 8080,
464	    }),
465	  );
466	  plugins.push(createLlmProxyAnthropicFormatPlugin());
467	
468	  const orchestratorCfg: Parameters<typeof createChatOrchestratorPlugin>[0] = {
469	    runnerBinary: config.chat?.runnerBinary ?? defaultRunnerBinary(),
470	    chatTimeoutMs: config.chat?.chatTimeoutMs ?? DEFAULT_CHAT_TIMEOUT_MS,
471	  };
472	  if (config.chat?.oneShot !== undefined) {
473	    orchestratorCfg.oneShot = config.chat.oneShot;
474	  }
475	  plugins.push(createChatOrchestratorPlugin(orchestratorCfg));
476	
477	  // ----- 7. tool catalog -------------------------------------------------
478	  // Dispatcher first — it registers `tool:register` / `tool:list`. The
479	  // descriptor-only tool plugins (bash, file-io) call `tool:register` from
480	  // their init. mcp-client also calls `tool:register` from init.
481	  //
482	  // mcp-client gets `mountAdminRoutes: true` so /admin/mcp-servers* lands
483	  // alongside the rest of the admin surface. The flag expands the plugin's
484	  // manifest `calls` to include http:register-route + auth:require-user;
485	  // the kernel's topo-sort picks up the new edges automatically.
486	  plugins.push(createToolDispatcherPlugin());
487	  plugins.push(createToolBashPlugin());
488	  plugins.push(createToolFileIoPlugin());
489	  plugins.push(createMcpClientPlugin({ mountAdminRoutes: true }));
490	
491	  // ----- 8. agents -------------------------------------------------------
492	  // Registers `agents:resolve` (the ACL gate the chat-orchestrator hard-
493	  // depends on as of Week 9.5) AND mounts /admin/agents* routes. The
494	  // plugin's manifest `calls` already declares http:register-route +
495	  // auth:require-user as hard deps — the kernel's topo-sort blocks init
496	  // until both upstream plugins have registered. Reuses the shared
497	  // postgres pool via `database:get-instance` (no second pool).
498	  plugins.push(createAgentsPlugin());
499	
500	  // ----- 9. LLM ----------------------------------------------------------
501	  // Throws at init if ANTHROPIC_API_KEY is missing.
502	  const anthropicCfg: Parameters<typeof createLlmAnthropicPlugin>[0] = {};
503	  if (config.anthropic?.model !== undefined) {
504	    anthropicCfg.model = config.anthropic.model;
505	  }
506	  if (config.anthropic?.maxTokens !== undefined) {
507	    anthropicCfg.maxTokens = config.anthropic.maxTokens;
508	  }
509	  plugins.push(createLlmAnthropicPlugin(anthropicCfg));
510	
511	  return plugins;
512	}
513	
514	// ---------------------------------------------------------------------------
515	// Env → workspace-config helper.
516	//
517	// The Helm chart writes these env vars onto the host pod (see
518	// deploy/charts/ax-next/templates/host/deployment.yaml). The host entrypoint
519	// reads them via this helper to build the discriminated `workspace` config
520	// before calling `createK8sPlugins`.
521	//
522	//   AX_WORKSPACE_BACKEND        local | http   (default: local)
523	//   AX_WORKSPACE_ROOT           required when backend === 'local'
524	//   AX_WORKSPACE_GIT_HTTP_URL   required when backend === 'http'
525	//   AX_WORKSPACE_GIT_HTTP_TOKEN required when backend === 'http'
526	//
527	// We throw loudly on missing/unknown values rather than silently defaulting
528	// — a misconfigured workspace backend is a deploy-time bug, not a runtime
529	// surprise we want to paper over.
530	// ---------------------------------------------------------------------------
531	
532	/**
533	 * Read the `AX_WORKSPACE_*` env vars and return a `K8sWorkspaceConfig`.
534	 *
535	 * Defaults to `local` when `AX_WORKSPACE_BACKEND` is unset (matches the
536	 * chart's default). Throws when the chosen backend's required vars are
537	 * missing or when the backend value is unknown.
538	 *
539	 * @param env - the env map to read from. Defaults to `process.env`. Pass an
540	 *   explicit object to keep tests deterministic (don't rely on the real
541	 *   `process.env` leaking between cases).
542	 */
543	export function workspaceConfigFromEnv(
544	  env: NodeJS.ProcessEnv = process.env,
545	): K8sWorkspaceConfig {
546	  // Treat empty string as unset. Helm templates frequently render
547	  // `value: "{{ .Values.workspace.backend }}"` with an empty value when
548	  // the user hasn't overridden it; we want that case to default to local
549	  // rather than fall through to the unknown-backend branch.
550	  const rawBackend = env.AX_WORKSPACE_BACKEND;
551	  const backend = rawBackend === undefined || rawBackend === '' ? 'local' : rawBackend;
552	
553	  if (backend === 'local') {
554	    const repoRoot = env.AX_WORKSPACE_ROOT;
555	    if (repoRoot === undefined || repoRoot === '') {
556	      throw new Error(
557	        'AX_WORKSPACE_BACKEND=local requires AX_WORKSPACE_ROOT to be set',
558	      );
559	    }
560	    return { backend: 'local', repoRoot };
561	  }
562	
563	  if (backend === 'http') {
564	    const baseUrl = env.AX_WORKSPACE_GIT_HTTP_URL;
565	    const token = env.AX_WORKSPACE_GIT_HTTP_TOKEN;
566	    if (baseUrl === undefined || baseUrl === '') {
567	      throw new Error(
568	        'AX_WORKSPACE_BACKEND=http requires AX_WORKSPACE_GIT_HTTP_URL to be set',
569	      );
570	    }
571	    if (token === undefined || token === '') {
572	      throw new Error(
573	        'AX_WORKSPACE_BACKEND=http requires AX_WORKSPACE_GIT_HTTP_TOKEN to be set',
574	      );
575	    }
576	    return { backend: 'http', baseUrl, token };
577	  }
578	
579	  throw new Error(
580	    `unknown AX_WORKSPACE_BACKEND=${backend}; expected 'local' or 'http'`,
581	  );
582	}
583	
584	// ---------------------------------------------------------------------------
585	// Full env loader. Builds a `K8sPresetConfig` from the env vars the Helm chart
586	// stamps onto the host pod. Mirrors `workspaceConfigFromEnv`'s posture: throw
587	// loudly on missing required values rather than silently default.
588	//
589	// Required env (per the chart):
590	//   - DATABASE_URL                — postgres DSN (database/eventbus/session)
591	//   - AX_K8S_HOST_IPC_URL          — cluster URL runners use to reach @ax/ipc-http
592	//   - AX_WORKSPACE_BACKEND + the per-backend vars (delegated to workspaceConfigFromEnv)
593	//   - AX_HTTP_HOST / AX_HTTP_PORT  — public-facing http listener
594	//   - AX_HTTP_COOKIE_KEY           — 32-byte signing key (hex / base64)
595	//   - AX_HTTP_ALLOWED_ORIGINS      — CSRF allow-list (comma-separated)
596	//   - At least one of:
597	//       AX_AUTH_GOOGLE_{CLIENT_ID,CLIENT_SECRET,REDIRECT_URI,ISSUER}
598	//       AX_DEV_BOOTSTRAP_TOKEN
599	//
600	// Optional env:
601	//   - K8S_NAMESPACE / K8S_POD_IMAGE / K8S_RUNTIME_CLASS / K8S_IMAGE_PULL_SECRETS
602	//                                  — sandbox-k8s overrides
603	//   - BIND_HOST / PORT             — @ax/ipc-http listen address (defaults
604	//                                    '0.0.0.0' / 8080)
605	//   - AX_LLM_MODEL / AX_LLM_MAX_TOKENS — anthropic config
606	//   - AX_RUNNER_BINARY             — chat orchestrator override (tests)
607	//   - AX_CHAT_TIMEOUT_MS           — chat orchestrator override
608	//   - AX_AUTH_SESSION_LIFETIME_SECONDS — auth session cookie lifetime
609	//
610	// `ANTHROPIC_API_KEY` and `AX_CREDENTIALS_KEY` are read by the respective
611	// plugins themselves at init() time — they don't appear in K8sPresetConfig.
612	// ---------------------------------------------------------------------------
613	
614	/**
615	 * Build a full `K8sPresetConfig` from the env vars the Helm chart sets on the
616	 * host pod. Throws on missing required values.
617	 *
618	 * @param env - the env map to read from. Defaults to `process.env`. Pass an
619	 *   explicit object to keep tests deterministic.
620	 */
621	export function loadK8sConfigFromEnv(
622	  env: NodeJS.ProcessEnv = process.env,
623	): K8sPresetConfig {
624	  const databaseUrl = env.DATABASE_URL;
625	  if (databaseUrl === undefined || databaseUrl === '') {
626	    throw new Error('DATABASE_URL is required');
627	  }
628	  const hostIpcUrl = env.AX_K8S_HOST_IPC_URL;
629	  if (hostIpcUrl === undefined || hostIpcUrl === '') {
630	    throw new Error('AX_K8S_HOST_IPC_URL is required');
631	  }
632	
633	  const sandbox: NonNullable<K8sPresetConfig['sandbox']> = {};
634	  if (env.K8S_NAMESPACE !== undefined && env.K8S_NAMESPACE !== '') {
635	    sandbox.namespace = env.K8S_NAMESPACE;
636	  }
637	  if (env.K8S_POD_IMAGE !== undefined && env.K8S_POD_IMAGE !== '') {
638	    sandbox.image = env.K8S_POD_IMAGE;
639	  }
640	  if (env.K8S_RUNTIME_CLASS !== undefined && env.K8S_RUNTIME_CLASS !== '') {
641	    sandbox.runtimeClassName = env.K8S_RUNTIME_CLASS;
642	  }
643	  if (env.K8S_IMAGE_PULL_SECRETS !== undefined && env.K8S_IMAGE_PULL_SECRETS !== '') {
644	    sandbox.imagePullSecrets = env.K8S_IMAGE_PULL_SECRETS.split(',').map((s) => s.trim()).filter((s) => s.length > 0);
645	  }
646	
647	  const ipc: K8sPresetConfig['ipc'] = { hostIpcUrl };
648	  if (env.BIND_HOST !== undefined && env.BIND_HOST !== '') {
649	    ipc.host = env.BIND_HOST;
650	  }
651	  if (env.PORT !== undefined && env.PORT !== '') {
652	    const portNum = Number(env.PORT);
653	    if (!Number.isFinite(portNum) || portNum <= 0 || portNum > 65535) {
654	      throw new Error(`invalid PORT=${env.PORT}; expected a positive integer`);
655	    }
656	    ipc.port = portNum;
657	  }
658	
659	  const anthropic: NonNullable<K8sPresetConfig['anthropic']> = {};
660	  if (env.AX_LLM_MODEL !== undefined && env.AX_LLM_MODEL !== '') {
661	    anthropic.model = env.AX_LLM_MODEL;
662	  }
663	  if (env.AX_LLM_MAX_TOKENS !== undefined && env.AX_LLM_MAX_TOKENS !== '') {
664	    const n = Number(env.AX_LLM_MAX_TOKENS);
665	    if (!Number.isFinite(n) || n <= 0) {
666	      throw new Error(`invalid AX_LLM_MAX_TOKENS=${env.AX_LLM_MAX_TOKENS}; expected a positive integer`);
667	    }
668	    anthropic.maxTokens = n;
669	  }
670	
671	  const chat: NonNullable<K8sPresetConfig['chat']> = {};
672	  if (env.AX_RUNNER_BINARY !== undefined && env.AX_RUNNER_BINARY !== '') {
673	    chat.runnerBinary = env.AX_RUNNER_BINARY;
674	  }
675	  if (env.AX_CHAT_TIMEOUT_MS !== undefined && env.AX_CHAT_TIMEOUT_MS !== '') {
676	    const n = Number(env.AX_CHAT_TIMEOUT_MS);
677	    if (!Number.isFinite(n) || n <= 0) {
678	      throw new Error(`invalid AX_CHAT_TIMEOUT_MS=${env.AX_CHAT_TIMEOUT_MS}; expected a positive integer`);
679	    }
680	    chat.chatTimeoutMs = n;
681	  }
682	
683	  // ---- http listener (public-facing /admin + /auth surface) -----------
684	  const httpHost = env.AX_HTTP_HOST;
685	  if (httpHost === undefined || httpHost === '') {
686	    throw new Error('AX_HTTP_HOST is required');
687	  }
688	  const httpPortRaw = env.AX_HTTP_PORT;
689	  if (httpPortRaw === undefined || httpPortRaw === '') {
690	    throw new Error('AX_HTTP_PORT is required');
691	  }
692	  const httpPort = Number(httpPortRaw);
693	  // Allow 0 (OS-assigned) — tests rely on it. Reject negatives, non-finite,
694	  // and >65535. (The k8s chart never sets 0; the ax-next test suite does.)
695	  if (!Number.isFinite(httpPort) || !Number.isInteger(httpPort) || httpPort < 0 || httpPort > 65535) {
696	    throw new Error(`invalid AX_HTTP_PORT=${httpPortRaw}; expected 0..65535`);
697	  }
698	  const cookieKey = env.AX_HTTP_COOKIE_KEY;
699	  if (cookieKey === undefined || cookieKey === '') {
700	    throw new Error('AX_HTTP_COOKIE_KEY is required (32 bytes; 64 hex chars or 44 base64 chars)');
701	  }
702	  const allowedOriginsRaw = env.AX_HTTP_ALLOWED_ORIGINS;
703	  // Treat unset OR empty as "no allow-list" — http-server then prints its
704	  // loud warn unless AX_HTTP_ALLOW_NO_ORIGINS=1 silences it. We don't try
705	  // to be opinionated here; the chart is where the operator-visible warning
706	  // really belongs.
707	  const allowedOrigins =
708	    allowedOriginsRaw === undefined || allowedOriginsRaw === ''
709	      ? []
710	      : allowedOriginsRaw
711	          .split(',')
712	          .map((s) => s.trim())
713	          .filter((s) => s.length > 0);
714	
715	  // ---- auth providers --------------------------------------------------
716	  // At least one of `google` or `devBootstrap` must be present; the auth
717	  // plugin throws `no-auth-providers` at init otherwise. We re-validate
718	  // here so the operator gets a startup error pointing at the env vars
719	  // they actually set, not at the auth plugin's internal config name.
720	  const auth: K8sPresetConfig['auth'] = {};
721	  const gClientId = env.AX_AUTH_GOOGLE_CLIENT_ID;
722	  const gClientSecret = env.AX_AUTH_GOOGLE_CLIENT_SECRET;
723	  const gRedirectUri = env.AX_AUTH_GOOGLE_REDIRECT_URI;
724	  const gIssuer = env.AX_AUTH_GOOGLE_ISSUER;
725	  const anyGoogle =
726	    (gClientId !== undefined && gClientId !== '') ||
727	    (gClientSecret !== undefined && gClientSecret !== '') ||
728	    (gRedirectUri !== undefined && gRedirectUri !== '') ||
729	    (gIssuer !== undefined && gIssuer !== '');
730	  if (anyGoogle) {
731	    // Partial google config is a deploy-time bug; fail loudly. The auth
732	    // plugin would also catch this (Issuer.discover throws on a bogus
733	    // issuer URL), but a clear startup error beats a network-shaped
734	    // failure deep inside init.
735	    if (gClientId === undefined || gClientId === '') {
736	      throw new Error('AX_AUTH_GOOGLE_CLIENT_ID is required when any AX_AUTH_GOOGLE_* var is set');
737	    }
738	    if (gClientSecret === undefined || gClientSecret === '') {
739	      throw new Error('AX_AUTH_GOOGLE_CLIENT_SECRET is required when any AX_AUTH_GOOGLE_* var is set');
740	    }
741	    if (gRedirectUri === undefined || gRedirectUri === '') {
742	      throw new Error('AX_AUTH_GOOGLE_REDIRECT_URI is required when any AX_AUTH_GOOGLE_* var is set');
743	    }
744	    if (gIssuer === undefined || gIssuer === '') {
745	      throw new Error('AX_AUTH_GOOGLE_ISSUER is required when any AX_AUTH_GOOGLE_* var is set');
746	    }
747	    auth.google = {
748	      clientId: gClientId,
749	      clientSecret: gClientSecret,
750	      redirectUri: gRedirectUri,
751	      issuer: gIssuer,
752	    };
753	  }
754	  const devToken = env.AX_DEV_BOOTSTRAP_TOKEN;
755	  if (devToken !== undefined && devToken !== '') {
756	    auth.devBootstrap = { token: devToken };
757	  }
758	  if (auth.google === undefined && auth.devBootstrap === undefined) {
759	    throw new Error(
760	      'auth requires at least one of AX_AUTH_GOOGLE_* (clientId/clientSecret/redirectUri/issuer) or AX_DEV_BOOTSTRAP_TOKEN',
761	    );
762	  }
763	  if (env.AX_AUTH_SESSION_LIFETIME_SECONDS !== undefined && env.AX_AUTH_SESSION_LIFETIME_SECONDS !== '') {
764	    const n = Number(env.AX_AUTH_SESSION_LIFETIME_SECONDS);
765	    if (!Number.isFinite(n) || !Number.isInteger(n) || n <= 0) {
766	      throw new Error(`invalid AX_AUTH_SESSION_LIFETIME_SECONDS=${env.AX_AUTH_SESSION_LIFETIME_SECONDS}; expected a positive integer`);
767	    }
768	    auth.sessionLifetimeSeconds = n;
769	  }
770	
771	  const config: K8sPresetConfig = {
772	    database: { connectionString: databaseUrl },
773	    eventbus: { connectionString: databaseUrl },
774	    session: { connectionString: databaseUrl },
775	    workspace: workspaceConfigFromEnv(env),
776	    ipc,
777	    http: {
778	      host: httpHost,
779	      port: httpPort,
780	      cookieKey,
781	      allowedOrigins,
782	    },
783	    auth,
784	  };
785	  if (Object.keys(sandbox).length > 0) config.sandbox = sandbox;
786	  if (Object.keys(anthropic).length > 0) config.anthropic = anthropic;
787	  if (Object.keys(chat).length > 0) config.chat = chat;
788	  return config;
789	}
