55	interface MockBundle {
56	  services: Record<string, ServiceHandler>;
57	  calls: {
58	    sessionQueueWork: number;
59	    sessionTerminate: number;
60	    sandboxOpen: number;
61	    killCalls: number;
62	    agentsResolve: number;
63	    lastSandboxInput: unknown;
64	  };
65	  lastQueuedMessage(): ChatMessage | undefined;
66	}
67	
68	// Builds a default mock bundle. Callers can override individual services.
69	// The orchestrator itself does NOT call session:create (sandbox:open-session
70	// does), so we don't mock session:create here. agents:resolve IS mocked
71	// because Week 9.5's orchestrator hard-depends on it.
72	function buildMocks(opts: {
73	  openSession?: ServiceHandler;
74	  queueWork?: ServiceHandler;
75	  agentsResolve?: ServiceHandler;
76	} = {}): MockBundle {
77	  const calls = {
78	    sessionQueueWork: 0,
79	    sessionTerminate: 0,
80	    sandboxOpen: 0,
81	    killCalls: 0,
82	    agentsResolve: 0,
83	    lastSandboxInput: undefined as unknown,
84	  };
85	  let lastQueued: ChatMessage | undefined;
86	
87	  const services: Record<string, ServiceHandler> = {
88	    'agents:resolve': async (ctx, input) => {
89	      calls.agentsResolve += 1;
90	      if (opts.agentsResolve !== undefined) {
91	        return opts.agentsResolve(ctx, input);
92	      }
93	      return { agent: { ...TEST_AGENT } };
94	    },
95	    'session:queue-work':
96	      opts.queueWork ??
97	      (async (_ctx, input: unknown) => {
98	        calls.sessionQueueWork += 1;
99	        const entry = (input as { entry: { type: string; payload?: ChatMessage } })
100	          .entry;
101	        if (entry.type === 'user-message') {
102	          lastQueued = entry.payload;
103	        }
104	        return { cursor: 0 };
105	      }),
106	    'session:terminate': async () => {
107	      calls.sessionTerminate += 1;
108	      return {};
109	    },
110	    'sandbox:open-session': async (ctx, input: unknown) => {
111	      calls.lastSandboxInput = input;
112	      calls.sandboxOpen += 1;
113	      if (opts.openSession !== undefined) {
114	        // Delegate to override but still wrap the returned handle so we can
115	        // count kill() calls even when the test provides its own handle.
116	        const result = (await opts.openSession(ctx, input)) as {
117	          runnerEndpoint: string;
118	          handle: {
119	            kill: () => Promise<void>;
120	            exited: Promise<unknown>;
121	          };
122	        };
123	        const originalKill = result.handle.kill;
124	        return {
125	          runnerEndpoint: result.runnerEndpoint,
126	          handle: {
127	            ...result.handle,
128	            kill: async () => {
129	              calls.killCalls += 1;
130	              await originalKill();
131	            },
132	          },
133	        };
134	      }
135	      return {
136	        runnerEndpoint: 'unix:///tmp/mock.sock',
137	        handle: {
