139	            calls.killCalls += 1;
140	          },
141	          // Never resolves unless kill() — the real sandbox's exited resolves
142	          // on child-close; for tests we keep it pending to simulate a live
143	          // subprocess.
144	          exited: new Promise(() => undefined),
145	        },
146	      };
147	    },
148	  };
149	  return {
150	    services,
151	    calls,
152	    lastQueuedMessage: () => lastQueued,
153	  };
